package com.hospital.management.model;import java.math.*;import java.time.*;import java.util.*;/** Physical hospital room and its bed-capacity summary. */public class Room{private Long roomId,departmentId;private String roomNumber,roomType,departmentName,status;private Integer floorNumber;private BigDecimal dailyRate;private int totalBeds,availableBeds;private LocalDateTime createdAt,updatedAt;public Long getRoomId(){return roomId;}public void setRoomId(Long v){roomId=v;}public String getRoomNumber(){return roomNumber;}public void setRoomNumber(String v){roomNumber=v;}public String getRoomType(){return roomType;}public void setRoomType(String v){roomType=v;}public Integer getFloorNumber(){return floorNumber;}public void setFloorNumber(Integer v){floorNumber=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getDepartmentName(){return departmentName;}public void setDepartmentName(String v){departmentName=v;}public BigDecimal getDailyRate(){return dailyRate;}public void setDailyRate(BigDecimal v){dailyRate=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public int getTotalBeds(){return totalBeds;}public void setTotalBeds(int v){totalBeds=v;}public int getAvailableBeds(){return availableBeds;}public void setAvailableBeds(int v){availableBeds=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}public boolean equals(Object o){return this==o||(o instanceof Room r&&roomId!=null&&roomId.equals(r.roomId));}public int hashCode(){return Objects.hashCode(roomId);}public String toString(){return"Room{id="+roomId+", number="+roomNumber+"}";}}
